import { mkdir, readFile, writeFile } from "node:fs/promises";
import { dirname, isAbsolute, resolve } from "node:path";
import { pathToFileURL } from "node:url";
import { createHash } from "node:crypto";

const PLACEHOLDER_PATTERN = /^<[^<>]+>$/;
const DEFAULT_SUBJECT_ID = "bundle_applier";
const DEFAULT_SUBJECT_ROLES = "platform_admin";

function usage() {
  return [
    "Usage:",
    "  node scripts/apply_tenant_bundle_changes.mjs --request <path> --mode <dry-run|write> [options]",
    "",
    "Required:",
    "  --request <path>        Provisioning request JSON generated by the onboarding bundle",
    "  --mode <mode>           dry-run or write",
    "",
    "Options:",
    "  --base-url <url>        Override tenant base URL; defaults to request.tenant.base_url",
    "  --tenant-id <id>        Override tenant id; defaults to request.tenant.tenant_id",
    "  --subject-id <id>      Subject header value; defaults to SUBJECT_ID or bundle_applier",
    "  --subject-roles <roles> Subject roles header value; defaults to SUBJECT_ROLES or platform_admin",
    "  --apply-policies       Apply policy changes when desired policy fields are present",
    "  --output <path>        Evidence JSON output path; defaults next to the request file",
    "  --idempotency-seed <s> Stable seed used to derive per-operation idempotency keys",
    "  --trusted-edge         Use X-Authenticated-* headers instead of X-Subject-*",
    "  --help                 Show this message",
    "",
    "Notes:",
    "  - Provider changes are applied from desired_* fields.",
    "  - Policy changes are only applied when --apply-policies is set and desired policy fields are present.",
    "  - dry-run never contacts the control plane; write mode does.",
  ].join("\n");
}

function parseArgs(argv) {
  const args = {
    request: null,
    mode: null,
    baseUrl: null,
    tenantId: null,
    subjectId: process.env.SUBJECT_ID ?? DEFAULT_SUBJECT_ID,
    subjectRoles: process.env.SUBJECT_ROLES ?? DEFAULT_SUBJECT_ROLES,
    output: process.env.EVIDENCE_OUTPUT_PATH ?? null,
    applyPolicies: false,
    idempotencySeed: process.env.IDEMPOTENCY_SEED ?? null,
    trustedEdge: process.env.NORTHBOUND_AUTH_MODE === "trusted_edge" || process.env.TRUSTED_EDGE === "true",
    help: false,
  };

  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index];
    if (arg === "--help" || arg === "-h") {
      args.help = true;
      continue;
    }

    if (arg === "--apply-policies") {
      args.applyPolicies = true;
      continue;
    }

    if (arg === "--trusted-edge") {
      args.trustedEdge = true;
      continue;
    }

    const next = argv[index + 1];
    switch (arg) {
      case "--request":
        args.request = next ?? null;
        index += 1;
        break;
      case "--mode":
        args.mode = next ?? null;
        index += 1;
        break;
      case "--base-url":
        args.baseUrl = next ?? null;
        index += 1;
        break;
      case "--tenant-id":
        args.tenantId = next ?? null;
        index += 1;
        break;
      case "--subject-id":
        args.subjectId = next ?? args.subjectId;
        index += 1;
        break;
      case "--subject-roles":
        args.subjectRoles = next ?? args.subjectRoles;
        index += 1;
        break;
      case "--output":
        args.output = next ?? null;
        index += 1;
        break;
      case "--idempotency-seed":
        args.idempotencySeed = next ?? null;
        index += 1;
        break;
      default:
        throw new Error(`Unknown argument: ${arg}`);
    }
  }

  return args;
}

function normalizeMode(mode) {
  if (mode === "dry-run" || mode === "write") {
    return mode;
  }
  throw new Error(`Invalid --mode: ${mode}. Expected dry-run or write.`);
}

function isPlaceholderString(value) {
  return typeof value === "string" && PLACEHOLDER_PATTERN.test(value.trim());
}

function isNonEmptyString(value) {
  return typeof value === "string" && value.trim() !== "";
}

function normalizeString(value) {
  if (typeof value !== "string") {
    return null;
  }
  const trimmed = value.trim();
  return trimmed === "" ? null : trimmed;
}

function normalizeBaseUrl(value, fallback) {
  const candidate = normalizeString(value) ?? normalizeString(fallback);
  if (!candidate) {
    throw new Error("Missing --base-url or request.tenant.base_url");
  }

  const url = new URL(candidate);
  if (url.protocol !== "http:" && url.protocol !== "https:") {
    throw new Error(`BASE_URL must use http or https: ${candidate}`);
  }

  return url.origin;
}

function normalizeTenantId(value, fallback) {
  const candidate = normalizeString(value) ?? normalizeString(fallback);
  if (!candidate) {
    throw new Error("Missing --tenant-id or request.tenant.tenant_id");
  }
  return candidate;
}

function normalizeOutputPath(value, requestPath) {
  const candidate = normalizeString(value);
  if (candidate) {
    return isAbsolute(candidate) ? candidate : resolve(process.cwd(), candidate);
  }

  const derived = requestPath.endsWith(".json")
    ? requestPath.replace(/\.json$/u, ".apply-evidence.json")
    : `${requestPath}.apply-evidence.json`;
  return isAbsolute(derived) ? derived : resolve(process.cwd(), derived);
}

function readJsonFile(filePath) {
  return readFile(filePath, "utf8").then((content) => {
    try {
      return JSON.parse(content);
    } catch (error) {
      throw new Error(`Request file is not valid JSON: ${filePath}`);
    }
  });
}

function encodePathSegment(value) {
  return encodeURIComponent(value).replace(/%2F/g, "%2F");
}

function buildHeaders({ tenantId, subjectId, subjectRoles, trustedEdge, idempotencyKey }) {
  const headers = {
    "content-type": "application/json",
    "x-tenant-id": tenantId,
  };

  if (typeof idempotencyKey === "string" && idempotencyKey.trim() !== "") {
    headers["idempotency-key"] = idempotencyKey;
  }

  if (trustedEdge) {
    headers["x-authenticated-subject"] = subjectId;
    headers["x-authenticated-roles"] = subjectRoles;
  } else {
    headers["x-subject-id"] = subjectId;
    headers["x-subject-roles"] = subjectRoles;
  }

  return headers;
}

function createApiUrl(baseUrl, path) {
  return new URL(path, `${baseUrl.replace(/\/$/u, "")}/`).toString();
}

async function fetchJson(baseUrl, path, options) {
  const response = await fetch(createApiUrl(baseUrl, path), options);
  const text = await response.text();
  let json = null;
  if (text.trim() !== "") {
    try {
      json = JSON.parse(text);
    } catch {
      json = { raw: text };
    }
  }

  if (!response.ok) {
    const error = new Error(
      `HTTP ${response.status} ${response.statusText} for ${options.method ?? "GET"} ${path}`,
    );
    error.response = {
      status: response.status,
      statusText: response.statusText,
      body: json,
    };
    throw error;
  }

  return json;
}

function unwrapApiData(responseJson) {
  if (!responseJson || typeof responseJson !== "object") {
    return null;
  }
  if ("data" in responseJson) {
    return responseJson.data;
  }
  return responseJson;
}

function clone(value) {
  return value === undefined ? undefined : JSON.parse(JSON.stringify(value));
}

function collectPlaceholderPaths(value, basePath = "") {
  const results = [];
  if (typeof value === "string") {
    if (isPlaceholderString(value)) {
      results.push(basePath || "$");
    }
    return results;
  }

  if (Array.isArray(value)) {
    for (let index = 0; index < value.length; index += 1) {
      results.push(...collectPlaceholderPaths(value[index], `${basePath}[${index}]`));
    }
    return results;
  }

  if (value && typeof value === "object") {
    for (const [key, child] of Object.entries(value)) {
      const nextPath = basePath ? `${basePath}.${key}` : key;
      results.push(...collectPlaceholderPaths(child, nextPath));
    }
  }

  return results;
}

function sha256Text(text) {
  return createHash("sha256").update(text).digest("hex");
}

function buildIdempotencyKey(seed, parts) {
  const suffix = parts.filter((part) => typeof part === "string" && part.trim() !== "").join(":");
  // Keep the header value short-ish but stable: seed hash + suffix.
  return `bundle-apply:${seed}:${suffix}`.slice(0, 200);
}

function pickDesiredFields(item, fieldNames) {
  const patch = {};
  for (const fieldName of fieldNames) {
    if (Object.prototype.hasOwnProperty.call(item, fieldName)) {
      patch[fieldName] = item[fieldName];
    }
  }
  return patch;
}

function normalizeNullableField(value, fieldName) {
  if (value === undefined) {
    return undefined;
  }
  if (value === null) {
    return null;
  }
  if (typeof value !== "string") {
    throw new Error(`${fieldName} must be a string or null`);
  }
  const trimmed = value.trim();
  if (isPlaceholderString(trimmed)) {
    throw new Error(`${fieldName} must not be a placeholder value`);
  }
  return trimmed === "" ? null : trimmed;
}

function normalizeDesiredString(value, fieldName, strict) {
  const normalized = requireNonEmptyString(value, fieldName);
  if (strict && isPlaceholderString(normalized)) {
    throw new Error(`${fieldName} must not be a placeholder value`);
  }
  return normalized;
}

function normalizeDesiredNullableField(value, fieldName, strict) {
  if (value === undefined) {
    return undefined;
  }
  if (value === null) {
    return null;
  }
  if (typeof value !== "string") {
    throw new Error(`${fieldName} must be a string or null`);
  }
  const trimmed = value.trim();
  if (strict && isPlaceholderString(trimmed)) {
    throw new Error(`${fieldName} must not be a placeholder value`);
  }
  return trimmed === "" ? null : trimmed;
}

function requireNonEmptyString(value, fieldName) {
  if (!isNonEmptyString(value)) {
    throw new Error(`${fieldName} must be a non-empty string`);
  }
  return value.trim();
}

function requireConcreteString(value, fieldName) {
  const normalized = requireNonEmptyString(value, fieldName);
  if (isPlaceholderString(normalized)) {
    throw new Error(`${fieldName} must not be a placeholder value`);
  }
  return normalized;
}

function requireObject(value, fieldName) {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    throw new Error(`${fieldName} must be an object`);
  }
  return value;
}

function summarizeDiff(before, after, keys) {
  const diff = [];
  for (const key of keys) {
    const beforeValue = before ? before[key] : undefined;
    const afterValue = after ? after[key] : undefined;
    if (JSON.stringify(beforeValue) !== JSON.stringify(afterValue)) {
      diff.push({
        field: key,
        before: clone(beforeValue),
        after: clone(afterValue),
      });
    }
  }
  return diff;
}

async function ensureDirForFile(filePath) {
  await mkdir(dirname(filePath), { recursive: true });
}

function readProviderDesiredPatch(item, strict = true) {
  const patch = pickDesiredFields(item, [
    "desired_name",
    "desired_provider_type",
    "desired_endpoint_url",
    "desired_auth_ref",
    "desired_visibility_policy_ref",
    "desired_execution_policy_ref",
    "desired_status",
  ]);

  const normalized = {};
  if ("desired_name" in patch) normalized.name = normalizeDesiredString(patch.desired_name, "desired_name", strict);
  if ("desired_provider_type" in patch)
    normalized.provider_type = normalizeDesiredString(patch.desired_provider_type, "desired_provider_type", strict);
  if ("desired_endpoint_url" in patch)
    normalized.endpoint_url = normalizeDesiredString(patch.desired_endpoint_url, "desired_endpoint_url", strict);
  if ("desired_auth_ref" in patch)
    normalized.auth_ref = normalizeDesiredNullableField(patch.desired_auth_ref, "desired_auth_ref", strict);
  if ("desired_visibility_policy_ref" in patch)
    normalized.visibility_policy_ref = normalizeDesiredNullableField(
      patch.desired_visibility_policy_ref,
      "desired_visibility_policy_ref",
      strict,
    );
  if ("desired_execution_policy_ref" in patch)
    normalized.execution_policy_ref = normalizeDesiredNullableField(
      patch.desired_execution_policy_ref,
      "desired_execution_policy_ref",
      strict,
    );
  if ("desired_status" in patch)
    normalized.status = normalizeDesiredString(patch.desired_status, "desired_status", strict);
  return normalized;
}

function readPolicyDesiredSpec(item, strict = true) {
  const desiredPolicy = item.desired_policy ? requireObject(item.desired_policy, "desired_policy") : null;
  const source = desiredPolicy ?? {};
  const desired = {};

  const policyId = normalizeString(source.policy_id ?? item.policy_id);
  if (policyId) {
    desired.policy_id = policyId;
  }

  const channel = source.channel ?? source.desired_channel;
  if (channel !== undefined) {
    desired.channel = normalizeDesiredString(channel, "channel", strict);
  }

  const scope = source.scope ?? source.desired_scope;
  if (scope !== undefined) {
    desired.scope = requireObject(scope, "scope");
  }

  const conditions = source.conditions ?? source.desired_conditions;
  if (conditions !== undefined) {
    desired.conditions = requireObject(conditions, "conditions");
  }

  const decision = source.decision ?? source.desired_decision;
  if (decision !== undefined) {
    desired.decision = normalizeDesiredString(decision, "decision", strict);
  }

  const priority = source.priority ?? source.desired_priority;
  if (priority !== undefined) {
    if (!Number.isInteger(priority) || priority < 0) {
      throw new Error("priority must be a non-negative integer");
    }
    desired.priority = priority;
  }

  const status = source.status ?? source.desired_status;
  if (status !== undefined) {
    desired.status = normalizeDesiredString(status, "status", strict);
  }

  const approvalConfig = source.approval_config ?? source.desired_approval_config;
  if (approvalConfig !== undefined) {
    desired.approval_config = requireObject(approvalConfig, "approval_config");
  }

  return desired;
}

function hasPolicyMutationFields(desiredSpec) {
  return [
    "channel",
    "scope",
    "conditions",
    "decision",
    "priority",
    "status",
    "approval_config",
  ].some((field) => desiredSpec[field] !== undefined);
}

function getActionId(action, fallbackIndex) {
  return normalizeString(action?.action_id) ?? `${action?.type ?? "action"}_${fallbackIndex + 1}`;
}

function buildProviderCreatePayload(item, desiredPatch) {
  const payload = {
    tool_provider_id: requireConcreteString(item.tool_provider_id, "tool_provider_id"),
    name: desiredPatch.name ?? (item.name !== undefined ? requireConcreteString(item.name, "name") : undefined),
    provider_type:
      desiredPatch.provider_type ??
      (item.provider_type !== undefined ? requireConcreteString(item.provider_type, "provider_type") : undefined),
    endpoint_url: desiredPatch.endpoint_url,
    auth_ref:
      desiredPatch.auth_ref !== undefined
        ? desiredPatch.auth_ref
        : normalizeNullableField(item.desired_auth_ref ?? item.auth_ref ?? null, "auth_ref"),
    visibility_policy_ref:
      desiredPatch.visibility_policy_ref !== undefined
        ? desiredPatch.visibility_policy_ref
        : normalizeNullableField(item.visibility_policy_ref ?? null, "visibility_policy_ref"),
    execution_policy_ref:
      desiredPatch.execution_policy_ref !== undefined
        ? desiredPatch.execution_policy_ref
        : normalizeNullableField(item.execution_policy_ref ?? null, "execution_policy_ref"),
    status:
      desiredPatch.status ??
      (item.status !== undefined ? requireConcreteString(item.status, "status") : "active"),
  };

  if (!payload.tool_provider_id) {
    throw new Error("tool_provider_id is required");
  }
  if (!isNonEmptyString(payload.name)) {
    throw new Error(`Provider ${payload.tool_provider_id} is missing a createable name`);
  }
  if (!isNonEmptyString(payload.provider_type)) {
    throw new Error(`Provider ${payload.tool_provider_id} is missing a createable provider_type`);
  }
  if (!isNonEmptyString(payload.endpoint_url)) {
    throw new Error(`Provider ${payload.tool_provider_id} is missing a createable endpoint_url`);
  }

  return payload;
}

function buildPolicyCreatePayload(item, desiredSpec) {
  const payload = {
    policy_id: requireConcreteString(item.policy_id ?? desiredSpec.policy_id, "policy_id"),
    channel: desiredSpec.channel ?? (item.channel !== undefined ? requireConcreteString(item.channel, "channel") : undefined),
    scope: desiredSpec.scope ?? item.scope ?? null,
    conditions: desiredSpec.conditions ?? item.conditions ?? null,
    decision:
      desiredSpec.decision ??
      (item.decision !== undefined ? requireConcreteString(item.decision, "decision") : undefined),
    approval_config: desiredSpec.approval_config ?? item.approval_config ?? undefined,
    priority:
      desiredSpec.priority !== undefined
        ? desiredSpec.priority
        : Number.isInteger(item.priority)
          ? item.priority
          : undefined,
    status:
      desiredSpec.status ??
      (item.status !== undefined ? requireConcreteString(item.status, "status") : "active"),
  };

  if (!payload.policy_id) {
    throw new Error("policy_id is required");
  }
  if (!isNonEmptyString(payload.channel)) {
    throw new Error(`Policy ${payload.policy_id} is missing a createable channel`);
  }
  if (!payload.scope || typeof payload.scope !== "object") {
    throw new Error(`Policy ${payload.policy_id} is missing a createable scope`);
  }
  if (!payload.conditions || typeof payload.conditions !== "object") {
    throw new Error(`Policy ${payload.policy_id} is missing a createable conditions object`);
  }
  if (!isNonEmptyString(payload.decision)) {
    throw new Error(`Policy ${payload.policy_id} is missing a createable decision`);
  }
  if (!Number.isInteger(payload.priority) || payload.priority < 0) {
    throw new Error(`Policy ${payload.policy_id} is missing a createable priority`);
  }

  return payload;
}

async function applyProviderWrite({ baseUrl, headers, idempotencyKeyBase, item, desiredPatch, dryRun }) {
  const providerId = requireNonEmptyString(item.tool_provider_id, "tool_provider_id");
  const desiredKeys = Object.keys(desiredPatch);
  if (desiredKeys.length === 0) {
    return {
      provider_id: providerId,
      operation: "skip",
      reason: "No desired_* provider fields were provided",
    };
  }

  if (dryRun) {
    return {
      provider_id: providerId,
      operation: "update",
      desired: clone(desiredPatch),
    };
  }

  let existing = null;
  try {
    existing = unwrapApiData(
      await fetchJson(baseUrl, `/api/v1/tool-providers/${encodePathSegment(providerId)}`, {
        method: "GET",
        headers,
      }),
    );
  } catch (error) {
    if (!error?.response || error.response.status !== 404) {
      throw error;
    }
  }

  if (existing) {
    const response = unwrapApiData(
      await fetchJson(baseUrl, `/api/v1/tool-providers/${encodePathSegment(providerId)}`, {
        method: "POST",
        headers: { ...headers, "idempotency-key": `${idempotencyKeyBase}:update` },
        body: JSON.stringify(desiredPatch),
      }),
    );
    return {
      provider_id: providerId,
      operation: "update",
      before: selectToolProviderFields(existing),
      after: selectToolProviderFields(response),
      diff: summarizeDiff(existing, response, [
        "name",
        "provider_type",
        "endpoint_url",
        "auth_ref",
        "visibility_policy_ref",
        "execution_policy_ref",
        "status",
      ]),
    };
  }

  const createPayload = buildProviderCreatePayload(item, desiredPatch);
  const response = unwrapApiData(
    await fetchJson(baseUrl, "/api/v1/tool-providers", {
      method: "POST",
      headers: { ...headers, "idempotency-key": `${idempotencyKeyBase}:create` },
      body: JSON.stringify(createPayload),
    }),
  );

  return {
    provider_id: providerId,
    operation: "create",
    before: null,
    after: selectToolProviderFields(response),
    request: createPayload,
  };
}

async function applyPolicyWrite({ baseUrl, headers, idempotencyKeyBase, item, desiredSpec, applyPolicies, dryRun }) {
  const policyId = requireNonEmptyString(item.policy_id, "policy_id");
  const shouldApply = applyPolicies && hasPolicyMutationFields(desiredSpec);

  if (!shouldApply) {
    return {
      policy_id: policyId,
      operation: "review",
      reviewed: true,
      desired: clone(desiredSpec),
    };
  }

  if (dryRun) {
    return {
      policy_id: policyId,
      operation: "update",
      desired: clone(desiredSpec),
    };
  }

  let existing = null;
  try {
    existing = unwrapApiData(
      await fetchJson(baseUrl, `/api/v1/policies/${encodePathSegment(policyId)}`, {
        method: "GET",
        headers,
      }),
    );
  } catch (error) {
    if (!error?.response || error.response.status !== 404) {
      throw error;
    }
  }

  if (desiredSpec.status === "disabled") {
    const response = unwrapApiData(
      await fetchJson(baseUrl, `/api/v1/policies/${encodePathSegment(policyId)}:disable`, {
        method: "POST",
        headers: { ...headers, "idempotency-key": `${idempotencyKeyBase}:disable` },
        body: JSON.stringify({ action: "disable_policy" }),
      }),
    );
    return {
      policy_id: policyId,
      operation: "disable",
      before: selectPolicyFields(existing),
      after: selectPolicyFields(response),
      diff: summarizeDiff(existing, response, [
        "channel",
        "decision",
        "priority",
        "status",
      ]),
    };
  }

  if (existing) {
    const updatePayload = { ...desiredSpec };
    delete updatePayload.policy_id;
    const response = unwrapApiData(
      await fetchJson(baseUrl, `/api/v1/policies/${encodePathSegment(policyId)}`, {
        method: "POST",
        headers: { ...headers, "idempotency-key": `${idempotencyKeyBase}:update` },
        body: JSON.stringify(updatePayload),
      }),
    );
    return {
      policy_id: policyId,
      operation: "update",
      before: selectPolicyFields(existing),
      after: selectPolicyFields(response),
      diff: summarizeDiff(existing, response, [
        "channel",
        "decision",
        "priority",
        "status",
      ]),
    };
  }

  const createPayload = buildPolicyCreatePayload(item, desiredSpec);
  const response = unwrapApiData(
    await fetchJson(baseUrl, "/api/v1/policies", {
      method: "POST",
      headers: { ...headers, "idempotency-key": `${idempotencyKeyBase}:create` },
      body: JSON.stringify(createPayload),
    }),
  );

  return {
    policy_id: policyId,
    operation: "create",
    before: null,
    after: selectPolicyFields(response),
    request: createPayload,
  };
}

function selectToolProviderFields(provider) {
  if (!provider || typeof provider !== "object") {
    return null;
  }
  return {
    tool_provider_id: provider.tool_provider_id ?? null,
    name: provider.name ?? null,
    provider_type: provider.provider_type ?? null,
    endpoint_url: provider.endpoint_url ?? null,
    auth_ref: provider.auth_ref ?? null,
    visibility_policy_ref: provider.visibility_policy_ref ?? null,
    execution_policy_ref: provider.execution_policy_ref ?? null,
    status: provider.status ?? null,
    updated_at: provider.updated_at ?? null,
  };
}

function selectPolicyFields(policy) {
  if (!policy || typeof policy !== "object") {
    return null;
  }
  return {
    policy_id: policy.policy_id ?? null,
    channel: policy.channel ?? null,
    scope: policy.scope ?? null,
    conditions: policy.conditions ?? null,
    decision: policy.decision ?? null,
    priority: policy.priority ?? null,
    status: policy.status ?? null,
    approval_config: policy.approval_config ?? null,
    updated_at: policy.updated_at ?? null,
  };
}

function buildActionEvidence(actionId, type, mode, status, detail) {
  return {
    action_id: actionId,
    type,
    mode,
    status,
    ...detail,
  };
}

async function main() {
  const argv = process.argv.slice(2);
  const parsed = parseArgs(argv);
  if (parsed.help) {
    console.log(usage());
    return;
  }

  const mode = normalizeMode(parsed.mode);
  const requestPath = parsed.request;
  if (!requestPath) {
    throw new Error("Missing required argument: --request");
  }

  const request = await readJsonFile(requestPath);
  const tenantId = normalizeTenantId(parsed.tenantId, request?.tenant?.tenant_id);
  const baseUrl = normalizeBaseUrl(parsed.baseUrl, request?.tenant?.base_url);
  const outputPath = normalizeOutputPath(parsed.output, requestPath);
  const startedAt = new Date().toISOString();
  const startedMs = Date.now();
  const requestPlaceholderPaths = collectPlaceholderPaths(request);
  const actions = Array.isArray(request?.actions) ? request.actions : [];
  const requestHash = sha256Text(JSON.stringify(request));
  const idempotencySeed = normalizeString(parsed.idempotencySeed) ?? requestHash.slice(0, 16);
  const headers = buildHeaders({
    tenantId,
    subjectId: normalizeString(parsed.subjectId) ?? DEFAULT_SUBJECT_ID,
    subjectRoles: normalizeString(parsed.subjectRoles) ?? DEFAULT_SUBJECT_ROLES,
    trustedEdge: parsed.trustedEdge,
    idempotencyKey: null,
  });

  const evidence = {
    ok: false,
    mode,
    base_url: baseUrl,
    tenant_id: tenantId,
    request_path: isAbsolute(requestPath) ? requestPath : resolve(process.cwd(), requestPath),
    output_path: outputPath,
    started_at: startedAt,
    completed_at: null,
    duration_ms: null,
    request_type: normalizeString(request?.request_type) ?? null,
    schema_version: normalizeString(request?.schema_version) ?? null,
    request_sha256: requestHash,
    idempotency_seed: idempotencySeed,
    request_placeholder_paths: requestPlaceholderPaths,
    action_results: [],
    summary: {
      provider_actions: 0,
      policy_actions: 0,
      policy_reviews: 0,
      changes_applied: 0,
      changes_planned: 0,
      blocked_by_placeholders: 0,
    },
    errors: [],
  };

  try {
    if (!request || typeof request !== "object") {
      throw new Error("Provisioning request must be a JSON object");
    }

    for (const [index, action] of actions.entries()) {
      const actionId = getActionId(action, index);
      const actionType = normalizeString(action?.type) ?? "unknown";

      if (actionType === "tool_provider_override") {
        const items = Array.isArray(action.items) ? action.items : [];
        for (const [itemIndex, item] of items.entries()) {
          const itemPlaceholders = collectPlaceholderPaths(item);
          const providerId = normalizeString(item.tool_provider_id);
          const desiredPatch = readProviderDesiredPatch(item, mode === "write");
          const blockingPlaceholderPaths = itemPlaceholders.filter((path) => path.includes("desired_"));

          if (!providerId) {
            throw new Error(`provider_overrides[${itemIndex}] is missing tool_provider_id`);
          }

          if (mode === "dry-run") {
            const hasDesiredChanges = Object.keys(desiredPatch).length > 0;
            evidence.action_results.push(
              buildActionEvidence(actionId, actionType, mode, hasDesiredChanges ? "planned" : "blocked", {
                tool_provider_id: providerId,
                item_index: itemIndex,
                desired: clone(desiredPatch),
                placeholder_paths: itemPlaceholders,
                note: hasDesiredChanges
                  ? "Would update provider from desired_* fields"
                  : "No desired_* fields were supplied for provider mutation",
              }),
            );
            evidence.summary.provider_actions += 1;
            evidence.summary.changes_planned += hasDesiredChanges ? 1 : 0;
            evidence.summary.blocked_by_placeholders += blockingPlaceholderPaths.length;
            continue;
          }

          if (blockingPlaceholderPaths.length > 0) {
            throw new Error(
              `provider_overrides[${itemIndex}] has unresolved desired_* placeholders: ${blockingPlaceholderPaths.join(", ")}`,
            );
          }

          const result = await applyProviderWrite({
            baseUrl,
            headers,
            idempotencyKeyBase: buildIdempotencyKey(idempotencySeed, [
              tenantId,
              actionId,
              actionType,
              `item${itemIndex}`,
              providerId,
            ]),
            item,
            desiredPatch,
            dryRun: false,
          });

          const status = result.operation === "skip" ? "skipped" : "applied";
          evidence.action_results.push(
            buildActionEvidence(actionId, actionType, mode, status, {
              tool_provider_id: providerId,
              item_index: itemIndex,
              ...result,
            }),
          );
          evidence.summary.provider_actions += 1;
          evidence.summary.changes_applied += result.operation === "skip" ? 0 : 1;
        }
        continue;
      }

      if (actionType === "policy_review") {
        const items = Array.isArray(action.items) ? action.items : [];
        for (const [itemIndex, item] of items.entries()) {
          const itemPlaceholders = collectPlaceholderPaths(item);
          const policyId = normalizeString(item.policy_id);
          if (!policyId) {
            throw new Error(`policy_review[${itemIndex}] is missing policy_id`);
          }

          const desiredSpec = readPolicyDesiredSpec(item, mode === "write");
          const hasDesiredChanges = hasPolicyMutationFields(desiredSpec);
          const reviewOnly = !(parsed.applyPolicies && hasDesiredChanges);

          if (mode === "dry-run") {
            evidence.action_results.push(
              buildActionEvidence(actionId, actionType, mode, reviewOnly ? "reviewed" : "planned", {
                policy_id: policyId,
                item_index: itemIndex,
                desired: clone(desiredSpec),
                placeholder_paths: itemPlaceholders,
                apply_policies: parsed.applyPolicies,
                note: reviewOnly
                  ? "Would record policy review only"
                  : "Would apply policy mutation from desired policy fields",
              }),
            );
            evidence.summary.policy_actions += 1;
            evidence.summary.policy_reviews += 1;
            evidence.summary.changes_planned += reviewOnly ? 0 : 1;
            continue;
          }

          const desiredPlaceholderPaths = itemPlaceholders.filter((path) => path.includes("desired_"));
          if (parsed.applyPolicies && desiredPlaceholderPaths.length > 0) {
            throw new Error(
              `policy_review[${itemIndex}] has unresolved desired_* placeholders: ${desiredPlaceholderPaths.join(", ")}`,
            );
          }

          const result = await applyPolicyWrite({
            baseUrl,
            headers,
            idempotencyKeyBase: buildIdempotencyKey(idempotencySeed, [
              tenantId,
              actionId,
              actionType,
              `item${itemIndex}`,
              policyId,
            ]),
            item,
            desiredSpec,
            applyPolicies: parsed.applyPolicies,
            dryRun: false,
          });

          const status = result.operation === "review" ? "reviewed" : "applied";
          evidence.action_results.push(
            buildActionEvidence(actionId, actionType, mode, status, {
              policy_id: policyId,
              item_index: itemIndex,
              ...result,
            }),
          );
          evidence.summary.policy_actions += 1;
          evidence.summary.policy_reviews += 1;
          evidence.summary.changes_applied += result.operation === "review" ? 0 : 1;
        }
        continue;
      }

      evidence.action_results.push(
        buildActionEvidence(actionId, actionType, mode, "ignored", {
          note: `Unsupported action type: ${actionType}`,
        }),
      );
    }

    evidence.ok = true;
    evidence.completed_at = new Date().toISOString();
    evidence.duration_ms = Date.now() - startedMs;
    evidence.summary.request_placeholders = requestPlaceholderPaths.length;
  } catch (error) {
    evidence.ok = false;
    evidence.completed_at = new Date().toISOString();
    evidence.duration_ms = Date.now() - startedMs;
    evidence.errors.push({
      message: error instanceof Error ? error.message : String(error),
      details: error?.response ?? null,
    });
    await ensureDirForFile(outputPath);
    await writeFile(outputPath, `${JSON.stringify(evidence, null, 2)}\n`, "utf8");
    console.error(JSON.stringify(evidence, null, 2));
    process.exitCode = 1;
    return;
  }

  await ensureDirForFile(outputPath);
  await writeFile(outputPath, `${JSON.stringify(evidence, null, 2)}\n`, "utf8");
  console.log(JSON.stringify(evidence, null, 2));
}

main().catch((error) => {
  console.error(error instanceof Error ? error.message : String(error));
  process.exit(1);
});
